import{_ as a,o as i,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/lekt0501.jpg",v=JSON.parse('{"title":"Lektion 5","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion05.md","filePath":"lektionen/lektion05.md"}'),s={name:"lektionen/lektion05.md"};function o(d,e,l,u,p,m){return i(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-5" tabindex="-1">Lektion 5 <a class="header-anchor" href="#lektion-5" aria-label="Permalink to &quot;Lektion 5&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>5.1. Nominalkomposita = samāsa m. = समास</li><li>5.2. Zur Sanskrit-Terminologie für Komposita</li><li>5.3. Kopulative Komposita = Dvandva n. (&quot;Paar&quot;) = द्वन्द्व <ul><li>5.3.1. Vorderglieder von Komposita</li><li>5.3.2. Plural-Itaretaradvandva</li></ul></li><li>5.4. Wortliste</li><li>5.5. Übung</li></ul><h2 id="_5-1-nominalkomposita-samasa-m-समास" tabindex="-1">5.1. Nominalkomposita = samāsa m. = समास <a class="header-anchor" href="#_5-1-nominalkomposita-samasa-m-समास" aria-label="Permalink to &quot;5.1. Nominalkomposita = samāsa m. = समास&quot;">​</a></h2><p>Die Bildung von Wortzusammensetzungen in sehr großem Umfang ist ein Charakteristikum des Sanskrit.</p><p>Die wichtigsten Bildungsformen von Komposita sind:</p><ul><li>kopulative Komposita = dvandva n. = द्वन्द्व</li><li>determinative Komposita = tatpuruṣa m. = तत्पुरुष</li><li>Possesivkomposita = bahuvrīhi m = बहुव्रीहि</li></ul><p>(Zu den beiden letztgenannten siehe später!)</p><h2 id="_5-2-zur-sanskrit-terminologie-fur-komposita" tabindex="-1">5.2. Zur Sanskrit-Terminologie für Komposita <a class="header-anchor" href="#_5-2-zur-sanskrit-terminologie-fur-komposita" aria-label="Permalink to &quot;5.2. Zur Sanskrit-Terminologie für Komposita&quot;">​</a></h2><p>ghaṭakapadāni n. pl.= घटकपदानि = Glieder eines Kompositums</p><p>vigrahavākyam n. = विग्रहवाक्यम् = Auflösung eines Kompsositums</p><p>nityasamāsaḥ m. = नित्यसमासः 0 Kompositum, für das es kein vigrahavākya gibt oder dessen vigrahavākya nicht möglich ist mit den Wörtern des Kompositums.</p><p>aluksamāsaḥ m. = अलुक्समासः  = Kompositum, in dem das Vorderglied eine Kasusendung behält</p><p>luksamāsaḥ m. = लुक्समासः = Kompositum, dessen Vorderglieder ohne Kasusendungen sind (der Normlfall)</p><p>madhyamapadalopī m. =  मध्यमपदलोपी = Kompositum, in dem ein oder mehrere mittlere Glieder ausgelassen werden</p><h2 id="_5-3-kopulative-komposita-dvandva-n-paar-द्वन्द्व" tabindex="-1">5.3. Kopulative Komposita = Dvandva n. (&quot;Paar&quot;) = द्वन्द्व <a class="header-anchor" href="#_5-3-kopulative-komposita-dvandva-n-paar-द्वन्द्व" aria-label="Permalink to &quot;5.3. Kopulative Komposita = Dvandva n. (&quot;Paar&quot;) = द्वन्द्व&quot;">​</a></h2><p>Die kopulativen Komposita dienen zur Verknüpfung von grammatisch gleichartigen, koordinierten Gliedern (Substantiven oder Adjektiven).</p><p>| Ein Dvandva bezeichnet:</p><ol><li>entweder die summative Verbindung der durch seine einzelnen Glieder bezeichneten Personen, Dinge, Eigenschaften: Itaretaradvandva = इतरेतरद्वन्द्व</li><li>oder: es fasst diese Personen, Dinge oder Eigenschaften zu einer Einheit zusammen: samāhāradvandva (&quot;Zusammenfassungsdvandva&quot;) = समाहारद्वन्द्व</li></ol><p>Im ersten Fall (Itaretaradvandva) erhält das Dvandva das grammatische Geschlecht seines letzten Gliedes und die Endungen des Dual, wenn  es sich um zwei Dinge usw. handlet, bzw. des Plurals, wenn es sich um mehr als zwei Dinge usw. handelt. Auch Singularendungen sind zulässig.</p><p>Im zweiten Fall (Samāhāradvandva) ist das Dvandva im Allgemeinen ein Neutrum, unabhängig vom Geschlecht seines letzten Gliedes, und steht im Singular.</p><p>| | --- | | Die Auflösung eines Dvandva erfolgt mit &quot;und&quot; (ca = च), gelegentlich mit &quot;oder&quot; (vā = वा) oder &quot;je&quot;. |</p><p>Zu den Dualdvandva siehe später!</p><h3 id="_5-3-1-vorderglieder-von-komposita" tabindex="-1">5.3.1. Vorderglieder von Komposita <a class="header-anchor" href="#_5-3-1-vorderglieder-von-komposita" aria-label="Permalink to &quot;5.3.1. Vorderglieder von Komposita&quot;">​</a></h3><p>Die Vorderglieder von Komposita (nicht nur Dvandvas) haben in der Regel die Form des unveränderten Nominalstamms. Die einzelnen Glieder von Komposita werden nach den Regeln des Satzsandhi verbunden (d.h. des Sandhi, den wir bisher kennengelernt haben, im Gegensatz zum Wortsandhi, der innerhalb des Wortes vor formativen Elementen Anwendung findet.</p><h3 id="_5-3-2-plural-itaretaradvandva" tabindex="-1">5.3.2. Plural-Itaretaradvandva <a class="header-anchor" href="#_5-3-2-plural-itaretaradvandva" aria-label="Permalink to &quot;5.3.2. Plural-Itaretaradvandva&quot;">​</a></h3><p>Beispiele für Pluraldvandva:</p><p>brāhmaṇa-kṣatriya-vaiśya-śūdrāḥ = ब्राह्मणक्षत्रियवैश्यशूद्राः</p><blockquote><p>= brāhmaṇāḥ kṣatriyā vaiśyāḥ śūdrāś ca = ब्राह्मणाः क्षत्रिया वैश्याः शूद्राश्च = &quot;Brahmanen, Kṣatriyas, Vaiśyas und Śūdras&quot;</p><p>oder = brāhmaṇaḥ kṣatriyo vaiśyaḥ śūdraś ca = ब्राह्मणः क्षत्रियो वश्यः शूद्रश्च = &quot;(ein/der) Brahmane, Kṣatriya, Vaiśya und Śūdra&quot;</p></blockquote><p>kavi-guravaḥ = कविगुरवः</p><blockquote><p>= kavayo guravaś ca = कवयो गुरवश्च &quot;Dichter und Lehrer&quot; (Plur.) (&quot;Ein Dichter und ein Lehrer&quot; müsste im Dual stehen!)</p></blockquote><p>Für die Reihenfolge der Glieder in einem Dvandva gelten u.a. folgende Regeln:</p><ul><li>die Bezeichnung der verschiedenen Stände (varṇa) soll gemäß der Reihenfolge der Stände mit der höchsten anfangend geordnet werden</li><li>der Name des älteren Bruders soll dem Namen des jüngeren Bruders vorangestellt werden</li><li>im Allgemeinen soll das wichtigere Wort an den Anfang gestellt werden</li><li>Wörter, die auf -i oder -u enden, sollen vorausgehen</li><li>Wörter, die auf -a enden und mit einem Vokal anfangen, sollen vorausgehen</li><li>Wörter, die weniger Silben enthalten, sollen vorausgehen</li></ul><p>Wo zwei der drei letztgenannten Vorschriften gleichzeitig in Frage kommen können, soll immer die später gegebene Regel befolgt werden.</p><p>(Beispiele von Dualdvandva zu diesen Regeln bei Kielhorn, Grammatik § 570).</p><h2 id="_5-4-wortliste" tabindex="-1">5.4. Wortliste <a class="header-anchor" href="#_5-4-wortliste" aria-label="Permalink to &quot;5.4. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>abhiniveṣa m. = अभिनिवेष : Neigung zu, Hartnäckigkeit, Bestehen auf; speziell: Anhänglichkeit an den Leib als sei er etwas Eigenes</p><p>kāma m. = काम : Wunsch, Begehren, erwünschte Gabe, Sinnenlust, Liebe; Liebesgott Kāma</p><p><img src="'+t+'" alt=""><br> Abb.: Gott Kāma = kāmadeva = कामदेव, 18. Jhdt.<br> [Bildquelle: Wikipedia, Public domain]</p><p>krodha m. = क्रोध : Zorn</p><p>kleśa m. = क्लेश : Qual, Plage</p><p>trayī f. = त्रयी : Dreizahl; insbes. die drei Veden (Ṛgveda, Sāmaveda, Yajurveda)</p><p>daṇḍanīti f. = दण्डनीति : Politik (ein Tatpuruṣa aus daṇḍa m. = = &quot;Stock, Macht, Herrschaft, Strafe&quot; und nīti f. &quot;(rechte) Führung&quot;)</p><p>dvijāti 3 = द्विजाति = dvija 3 = द्विज</p><p>dveṣa m. = द्वेष : Hass</p><p>maitrī f. = मैत्री : Freundschaft, Freundlichkeit, freundliches Wohlwollen</p><p>rāga m. = राग : (rote) Farbe, Leidenschaft, Liebe</p><p>lobha m. = लोभ : Gier, Habsucht</p><p>varṇa m. = वर्ण : Farbe, Gattung, Stand</p><p>vārttā f. = वार्त्ता : Erwerb, Ökonomie (Wirtschaft)</p><p>vidyā f. = विद्या : Wissen, Wissenschaft</p><p>dazu: avidyā f. = अविद्या : Unwissenheit, Nichtwissen</p><p>ca = च : und (wird dem Wort, welches es anknüpft, nachgestellt; werden mehrere Wörter durch ca angeknüpft, steht es hinter dem ersten Wort dieses Wortkomplexes; werden mehrere Wörter verknüpft., kann ca hinter jedem einzelnen stehen, besser aber nur hinter dem ersten Wort des letzten Verknüpfungsgliedes: brāhmaṇāḥ kṣatriyā vaiśyāḥ śūdrāś ca = ब्राह्मणाः क्षत्रिया वैश्याः शूद्राश्च)</p><p>ca ... ca = च ... च : sowohl als auch</p><h2 id="_5-5-ubung" tabindex="-1">5.5. Übung <a class="header-anchor" href="#_5-5-ubung" aria-label="Permalink to &quot;5.5. Übung&quot;">​</a></h2><p>A) Übersetzen Sie folgende Sätze und Komposita und lösen Sie die darin vorkommenden Dvandvas in Sanskrit auf:</p><p>1. catvāro varṇā brāhmaṇakṣatriyavaiśyaśūdrāḥ. (Āpastambīyadharmasūtra I,1,1,4 = Vāsiṣṭhadharmaśāstra II,1)</p><p>चत्वारो वर्णा ब्राह्मणक्षत्रियवैश्यशूद्राः ||</p><p>Erklärung catvāras = चत्वारस् = &quot;vier&quot;</p><p>2. trayo varṇā dvijātayo brāhmaṇakṣatriyavaiśyāḥ. (Vāsiṣṭhadharmaśāstra II,1)</p><p>त्रयो वर्णा द्विजातयो ब्राह्मणक्षत्रियवैश्याः ||</p><p>Erklärung: trayas = त्रयस् =  &quot;drei&quot;</p><p>3. sāmavedargvedayajurvedās trayī. (Kauṭilīya-arthaśāstra 1.3.1.) (in gutem Sanskrit: sāmārgyajurvedās trayī)</p><p>सामवेदर्ग्वेदयजुर्वेदास्त्रयी ||</p><p>(in gutem Sanskrit: सामार्यजुर्वेदास्त्रयी)</p><p>4. Die drei Feinde des Menschen, die das Tor zur Hölle bilden (Viṣṇusmṛti 33,1+6): kāmakrodhalobhāḥ</p><p>कामक्रोधलोभाः ||</p><p>5. maitrīkaruṇāmuditopekṣāś catvāro brahmavihārāḥ.</p><p>मैत्रीकरुणामुदितोपेक्षाश्चत्वारो ब्रह्मविहाराः ||</p><p>Erklärung: brahmavihāra: &quot;Verweilungszustände Brahmas&quot;, auch &quot;Unermessliche&quot; genannt: unbegrenzte Haltungen. Sie stellen buddhistische Meditationsformen dar, mit denen der Meditierende allmählich, schrittweise die ganze Wirklichkeit &quot;durchstrahlt&quot;. Auch im Yoga (Yogasūtra 1,33) spielen diese vier eine Rolle beim Zurruhekommen des Bewusstseins.</p><p>6. avidyāsmitārāgadveṣābhiniveṣāḥ pañca kleśāḥ. (Yogasūtra 2,3)</p><p>अविद्यास्मितारागद्वेषाभिनिवेषाः पञ्च क्लेशाः ||</p><p>Erklärung: pañca = &quot;fünf&quot;</p><p>7. ānvīkṣikītrayīvārttādaṇḍanitayo vidyāḥ. (Nach Kauṭilīya-arthaśāstra 1.2.1.)</p><p>आन्वीक्षिकीत्रयीवार्त्तादण्डनितयो विद्याः ||</p><h2 id="wiederholungsubung" tabindex="-1">Wiederholungsübung <a class="header-anchor" href="#wiederholungsubung" aria-label="Permalink to &quot;Wiederholungsübung&quot;">​</a></h2><p>A) Übersetzen Sie:</p><p>1. vidyā vārttā.</p><p>विद्या वार्त्ता |</p><p>2. brāhmaṇaḥ kṣatriyo vaiśyaś ca trayo varṇā dvijātayaḥ.</p><p>ब्राह्मणः क्षत्रियो वैश्यअश्च त्रयो वर्णा द्विजातयः |</p><p>3. dvijā vaiśyāḥ. (2 Möglichkeiten)</p><p>द्विजा वैश्याः |</p><p>B) Setzen Sie die entsprechende Form ein:</p><p>(dvija, sādhu, kavi) ... rāmaḥ</p><p>(द्विज, साधु, कवि) ... रामः |</p><p>(devī) ... indrāṇī</p><p>(देवी) ... इन्द्राणी |</p><p>dvijātayas ... (vaiśyā, kṣatriya)</p><p>द्विजातयस् ... (वैश्या, क्षत्रिय) |</p><p>C) Lösen Sie das Kompositum in folgendem Satz in Sanskrit auf und bilden Sie mit dieser aufgelösten Form denselben Satz:</p><p>sāmargyajurvedās trayī.</p><p>सामर्ग्यजुर्वेदास्त्रयी |</p><p>D) Übersetzen Sie auf zwei Weisen ins Sanskrit (einmअl  mit einem Kompositum, einmal ohne):</p><p>&quot;Verweilungszustände Brahmas&quot; sind: freundliches Wohlwollen, Mitgefühl, Mitfreude, Gleichmut.</p>',97)])])}const g=a(s,[["render",o]]);export{v as __pageData,g as default};
